import{C as t,o as l,c as n,a5 as s,E as d}from"./chunks/framework.CW28V7p_.js";const p=JSON.parse('{"title":"1. Build process","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/1-build.md","filePath":"module-0/1-build.md","lastUpdated":1780937944000}'),o={name:"module-0/1-build.md"},k=Object.assign(o,{setup(r){const i={id:"m0-1-build",title:"🧠 Mini-check: Build process",intro:"3 питання щоб перевірити чи зрозуміла основні концепти.",questions:[{type:"mcq",q:"Чому ми завжди використовуємо --release для validator builds (обери всі правильні)?",options:["Debug build повільніше у 10-100 разів і не витримає mainnet TPS","Release build має менший розмір binary","Debug build містить sensitive debug symbols які небезпечно деплоїти","Cargo install не приймає debug builds"],correct:[0,1],explanation:"Головна причина — performance. Release робить LTO + inlining, дає 10-100x швидше runtime. Розмір теж менший без debug symbols. Debug symbols самі по собі не secret. Cargo install приймає debug, просто це поганий вибір для prod."},{type:"explain",q:"Поясни своїми словами що робить linker і чому без linking не вийде запустити binary.",ideal:"Linker з'єднує object files (результат compile окремих файлів source code) і бібліотеки (готовий код типу libc, tokio, solana-sdk) в один виконуваний binary. Аналогія: compile = вирізав дошки і фурнітуру за кресленням, link = з'єднав їх у готову конструкцію. Без linking у тебе тільки купа .o файлів — CPU не вміє виконувати окремі object files, потрібен один self-contained executable з усіма symbols (функціями, даними) resolved.",explanation:"Ключове: linker з'єднує object files + libraries в один binary. Якщо ти описала що окремо compile робить object files а link їх з'єднує — це 80%+. Bonus якщо згадала про resolved symbols (функції з deps мають бути знайдені перш ніж binary запускається)."},{type:"command",q:"Як подивитись чи binary це ELF executable і яка архітектура? Напиши команду (припустимо binary на стандартному mainnet шляху).",accepts:["file ~/.local/share/solana/install/active_release/bin/agave-validator","sudo file ~/.local/share/solana/install/active_release/bin/agave-validator","file /home/solana/.local/share/solana/install/active_release/bin/agave-validator","sudo file /home/solana/.local/share/solana/install/active_release/bin/agave-validator"],ideal:"file ~/.local/share/solana/install/active_release/bin/agave-validator",explanation:"Команда file читає ELF header і показує що це за binary: 64-bit, архітектура (x86_64/arm64), статично чи динамічно слінкований, OS. На mainnet/testnet agave-install кладе binaries у ~/.local/share/solana/install/active_release/bin/."}]};return(h,a)=>{const e=t("Quiz");return l(),n("div",null,[a[0]||(a[0]=s("",66)),d(e,{data:i}),a[1]||(a[1]=s("",6))])}}});export{p as __pageData,k as default};
